  ('judicial-f0899a01-moex-00066', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於行政機關與內部單位之區別，下列敘述何者錯誤？', '["行政機關得獨立以其名義對外行文", "行政機關須有關防或大印", "內部單位須有獨立之預算", "內部單位無法成為行政處分機關，亦不得對之提起訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00067', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '直轄市法規、縣（市）規章就違反地方自治事項之行政業務者，得規定處以罰鍰或其他種類之行政罰。此 之行政罰不包含下列何者？', '["處以怠金", "吊扣執照", "勒令停工", "停止營業"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00068', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '經濟部將桃園航空貿易自由港區之工廠設立許可、登記事項交由桃園市政府辦理，其性質為何？', '["委任", "委託", "委辦", "職務協助"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00069', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依行政程序法規定，數行政機關於管轄權有爭議時，下列敘述何者正確？', '["由其共同上級機關決定之，無共同上級機關時，由各該上級機關協議定之", "人民就其依法規申請之事件，得向任一機關申請指定管轄", "不能協議或有統一管轄之必要時，由最高行政法院決定", "人民對行政機關所為指定管轄之決定，得聲明不服"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00070', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於公務員懲戒處分之敘述，下列何者錯誤？', '["免除職務，免其現職並不得再任用為公務員", "撤職，撤其現職，並於一定期間停止任用；其期間為1年以上、5年以下", "休職，休其現職，停發俸（薪）給，並不得申請退休、退伍或在其他機關任職", "應受懲戒行為，自行為終了之日起，至案件繫屬懲戒法院之日止，已逾5年者，不得予以休職之懲戒"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00071', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於公務員權利與義務之敘述，下列何者正確？', '["公務員懲戒，以其違法執行職務、怠於執行職務或其他失職行為者為限", "申誡雖為公務員之平時考核，仍得對其循序提起行政訴訟", "公務員以私法手段執行行政任務侵害人民權益時，仍適用國家賠償法", "公務員對所屬服務機關不享有休假請求權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00072', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '公務員對於長官下達違法命令之處理，下列敘述何者正確？', '["基於公務員之忠實義務必須遵守", "只要即時向長官陳述意見即無須遵守", "依法得自由決定是否要遵守", "若命令違反刑事法律即無須遵守"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00073', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '得準用公務人員保障法提起救濟之人員，不包括下列何者？', '["彰化縣議員", "公營事業依法任用之人員", "機關依法聘任人員", "應各種公務人員考試錄取參加訓練之人員"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00074', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依公務員服務法規定，下列敘述何者正確？', '["中央研究院未兼任行政職務之研究人員為公務員服務法之適用對象", "主管長官與兼管長官同時所發命令，以主管長官之命令為準", "公務員依法令兼職者，得兼薪", "公務員於其離職後5年內不得擔任與其離職前之職務直接相關之營利事業董事"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00075', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '為因應各種特殊情況需求及保有用人彈性，部分執行公務之人員的進用，得例外不須通過國家考試。下列 何者非屬得例外進用之人員？', '["聘用人員", "任用人員", "機要人員", "約僱人員"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
